SELECT *
FROM doc_updates
WHERE document_id = #{documentId}
  AND vector_clock = #{vectorClock}
ORDER BY id DESC
LIMIT 1

SELECT *
FROM doc_updates
WHERE document_id = #{documentId}
  AND parent_update_id = #{parentUpdateId}
ORDER BY created_at ASC, id ASC

mapper.update:
UPDATE doc_updates
vector_clock = #{vectorClock}, update_data = #{updateData,jdbcType=BLOB}, is_snapshot = #{isSnapshot}, parent_update_id = #{parentUpdateId}, created_at = created_at
WHERE id = #{id}
